export async function requestUpload(
  file: File,
  signal?: AbortSignal,
): Promise<UploadRequestResult> {
  const csrfToken = await getCsrfToken();
  const mimeType = getUploadMimeType(file);

  const payload: RequestUploadPayload = {
    filename: file.name,
    mimeType,
    sizeBytes: file.size,
  };
  const res = await fetch(`${API_BASE}/api/files/upload-request`, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      "X-CSRF-Token": csrfToken,
    },
    credentials: "include",
    body: JSON.stringify(payload),
    signal,
  });

  if (!res.ok) {
    const error = await res.json().catch(() => ({}));
    throw new Error(
      (error as { error?: string }).error || "Failed to create upload request",
    );
  }

  const data = (await res.json()) as UploadRequestResponse;
  return {
    fileId: data.fileId,
    uploadUrl: data.uploadUrl,
    cdnUrl: data.cdnUrl,
    method: data.method,
    isLocalUpload: Boolean(
      data.isLocalUpload ?? data.uploadUrl.startsWith("/api/files/upload"),
    ),
    localPath: data.localPath,
    assetUrl: data.assetUrl ?? data.cdnUrl,
  };
}

