import { useEffect, useState } from 'react';
import { createPortal } from 'react-dom';
import { getUploadNavigationWarningViewState, subscribeToUploads } from '@/services/uploadTracker';

function useUploadNavigationWarningState() {
  const [state, setState] = useState(() => getUploadNavigationWarningViewState());

  useEffect(() => {
    return subscribeToUploads(() => setState(getUploadNavigationWarningViewState()));
  }, []);

  return state;
}

export function useUploadNavigationWarning() {
  return useUploadNavigationWarningState();
}

export function UploadNavigationWarning() {
  const { isBlocked, uploadCount, activeUploads, proceed, stay } = useUploadNavigationWarning();
  const [isOpen, setIsOpen] = useState(false);

  useEffect(() => {
    setIsOpen(isBlocked);
  }, [isBlocked]);

  useEffect(() => {
    if (!isBlocked) return;

    const onKeyDown = (event: KeyboardEvent) => {
      if (event.key === 'Escape') {
        stay();
        setIsOpen(false);
      }
    };

    window.addEventListener('keydown', onKeyDown);

    return () => {
      window.removeEventListener('keydown', onKeyDown);
    };
  }, [isBlocked, stay]);

  if (!isBlocked || !isOpen || typeof document === 'undefined') return null;

  const primaryUpload = activeUploads[0];

  return createPortal(
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50" role="dialog" aria-modal="true" aria-labelledby="upload-warning-title">
      <div className="w-full max-w-md rounded-lg bg-background p-6 shadow-xl">
        <h2 id="upload-warning-title" className="text-lg font-semibold text-foreground">Uploads in Progress</h2>
        <p className="mt-2 text-sm text-muted">
          You have {uploadCount} upload{uploadCount !== 1 ? 's' : ''} in progress.
          {primaryUpload ? ` Current upload: ${primaryUpload.filename}.` : ''}
          Leaving this page will cancel {uploadCount !== 1 ? 'them' : 'it'}.
        </p>
        <div className="mt-6 flex justify-end gap-3">
          <button
            type="button"
            onClick={() => {
              stay();
              setIsOpen(false);
            }}
            className="rounded-md px-4 py-2 text-sm font-medium text-foreground hover:bg-muted/20"
          >
            Stay on Page
          </button>
          <button
            type="button"
            onClick={() => {
              proceed();
              setIsOpen(false);
            }}
            className="rounded-md bg-red-500 px-4 py-2 text-sm font-medium text-white hover:bg-red-600"
          >
            Leave & Cancel Uploads
          </button>
        </div>
      </div>
    </div>,
    document.body
  );
}

