import { randomUUID } from 'crypto';
import { Router, type Request, type Response } from 'express';
import { pool } from '../db/client.js';
import { authMiddleware } from '../middleware/auth.js';

const UUID_REGEX = /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i;
const commentsRouter = Router();

function parseUuid(value: unknown): string | null {
  return typeof value === 'string' && UUID_REGEX.test(value) ? value : null;
}

type CommentRow = {
  id: string;
  document_id: string;
  comment_id: string;
  parent_id: string | null;
  author_id: string;
  content: string;
  resolved_at: string | null;
  resolved_by: string | null;
  deleted_at: string | null;
  created_at: string;
  updated_at: string;
};

type CommentWithWorkspaceRow = CommentRow & {
  workspace_id: string;
};

type CommentThreadResponse = {
  comment_id: string;
  root: ReturnType<typeof mapCommentRow> | null;
  replies: ReturnType<typeof mapCommentRow>[];
};

function mapCommentRow(row: CommentRow) {
  return {
    id: row.id,
    document_id: row.document_id,
    comment_id: row.comment_id,
    parent_id: row.parent_id,
    author_id: row.author_id,
    content: row.content,
    resolved_at: row.resolved_at,
    resolved_by: row.resolved_by,
    deleted_at: row.deleted_at,
    created_at: row.created_at,
    updated_at: row.updated_at,
  };
}

async function getCommentWithWorkspace(id: string) {
  return pool.query<CommentWithWorkspaceRow>(
    'SELECT c.*, d.workspace_id FROM comments c JOIN documents d ON d.id = c.document_id WHERE c.id = $1',
    [id]
  );
}

async function isWorkspaceAdmin(workspaceId: string, userId: string): Promise<boolean> {
  const result = await pool.query('SELECT role FROM workspace_memberships WHERE workspace_id = $1 AND user_id = $2', [workspaceId, userId]);
  return result.rows[0]?.role === 'admin' || result.rows[0]?.role === 'owner';
}

