  created_at: string;
  updated_at: string;
};

type CommentWithWorkspaceRow = CommentRow & {
  workspace_id: string;
};

type CommentThreadResponse = {
  comment_id: string;
  root: ReturnType<typeof mapCommentRow> | null;
  replies: ReturnType<typeof mapCommentRow>[];
};

function mapCommentRow(row: CommentRow) {
  return {
    id: row.id,
    document_id: row.document_id,
    comment_id: row.comment_id,
    parent_id: row.parent_id,
    author_id: row.author_id,
    content: row.content,
    resolved_at: row.resolved_at,
    resolved_by: row.resolved_by,
    deleted_at: row.deleted_at,
    created_at: row.created_at,
    updated_at: row.updated_at,
  };
}

async function getCommentWithWorkspace(id: string) {
