    'SELECT c.*, d.workspace_id FROM comments c JOIN documents d ON d.id = c.document_id WHERE c.id = $1',
    [id]
  );
}

async function isWorkspaceAdmin(workspaceId: string, userId: string): Promise<boolean> {
  const result = await pool.query('SELECT role FROM workspace_memberships WHERE workspace_id = $1 AND user_id = $2', [workspaceId, userId]);
  return result.rows[0]?.role === 'admin' || result.rows[0]?.role === 'owner';
