export async function requestUpload(
  file: File,
  signal?: AbortSignal,
): Promise<UploadRequestResult> {
  const csrfToken = await getCsrfToken();
  const mimeType = getUploadMimeType(file);

  const payload: RequestUploadPayload = {
    filename: file.name,
    mimeType,
    sizeBytes: file.size,
  };
  const endpoints = ["/api/files/upload-request", "/api/files/upload"];
  let lastError: string | null = null;

  for (const endpoint of endpoints) {
    const res = await fetch(`${API_BASE}${endpoint}`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "X-CSRF-Token": csrfToken,
      },
      credentials: "include",
      body: JSON.stringify(payload),
      signal,
    });

    if (res.ok) {
      const data = (await res.json()) as UploadRequestResponse & {
        s3Key?: string;
      };
      const uploadUrl = data.uploadUrl ?? "";
      return {
        fileId: data.fileId,
        uploadUrl,
        cdnUrl: data.cdnUrl,
        method: data.method,
        isLocalUpload: Boolean(
          data.isLocalUpload ?? uploadUrl.startsWith("/api/files/upload"),
        ),
        localPath: data.localPath,
        assetUrl: data.assetUrl ?? data.cdnUrl,
      };
    }

    lastError = await res.json().catch(() => ({})).then((error) => {
      if (
        error &&
        typeof error === "object" &&
        "error" in error &&
        typeof (error as { error?: unknown }).error === "string"
      ) {
        return (error as { error: string }).error;
      }
      return null;
    });
  }

  throw new Error(lastError || "Failed to create upload request");
}

