      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "X-CSRF-Token": csrfToken,
      },
      credentials: "include",
      body: JSON.stringify(payload),
      signal,
    });

    if (res.ok) {
      const data = (await res.json()) as UploadRequestResponse & {
        s3Key?: string;
      };
      const uploadUrl = data.uploadUrl ?? "";
      return {
