/**
 * Global upload tracker for navigation warnings.
 * Used by both React components (via subscription) and non-React code (TipTap plugins).
 */

export interface UploadInfo {
  id: string;
  filename: string;
  progress: number;
  active: boolean;
}

export interface UploadTrackerSnapshot {
  uploadCount: number;
  activeUploads: UploadInfo[];
}

export interface UploadNavigationWarningState extends UploadTrackerSnapshot {
  isBlocked: boolean;
  proceed: () => void;
  stay: () => void;
}

export interface UploadNavigationWarningViewState extends UploadNavigationWarningState {
  isOpen: boolean;
}

export interface UploadNavigationWarningController extends UploadNavigationWarningState {
  subscribe: (listener: () => void) => () => void;
}

export interface UploadTrackerListenerState extends UploadTrackerSnapshot {
  hasActiveUploads: boolean;
}

const activeUploads = new Map<string, UploadInfo>();
const listeners = new Set<() => void>();
let beforeUnloadListener: ((event: BeforeUnloadEvent) => void) | null = null;
let navigationWarningListenersAttached = false;
let pendingWarningCount = 0;

function getUploadMessage(uploadCount: number): string {
  if (uploadCount <= 0) return '';
  return uploadCount === 1 ? '1 upload is still in progress.' : `${uploadCount} uploads are still in progress.`;
}

function cloneUpload(upload: UploadInfo): UploadInfo {
  return { ...upload };
}

function hasWindow(): boolean {
  return typeof window !== 'undefined';
}

function notifyListeners(): void {
  listeners.forEach((listener) => listener());
}

function getBeforeUnloadHandler() {
  return (event: BeforeUnloadEvent) => {
    if (!hasActiveUploads()) return;
    event.preventDefault();
    event.returnValue = getUploadMessage(getUploadCount());
    return event.returnValue;
  };
}

function refreshUploadPresence(): void {
  if (!hasWindow()) return;

  if (beforeUnloadListener) {
    window.removeEventListener('beforeunload', beforeUnloadListener);
    beforeUnloadListener = null;
  }

  if (!hasActiveUploads()) return;

  beforeUnloadListener = getBeforeUnloadHandler();
  window.addEventListener('beforeunload', beforeUnloadListener);
}

function refreshNavigationWarningListener(): void {
  if (!hasWindow()) return;

  if (!navigationWarningListenersAttached) {
    navigationWarningListenersAttached = true;
  }
}

function setPendingWarningCount(count: number): void {
  pendingWarningCount = count;
}

export function getPendingUploadWarningCount(): number {
  return pendingWarningCount;
}

export function registerUpload(id: string, filename: string): void {
  activeUploads.set(id, { id, filename, progress: 0, active: true });
  setPendingWarningCount(getUploadCount());
  refreshUploadPresence();
  notifyListeners();
}

export function updateUploadProgress(id: string, progress: number): void {
  const upload = activeUploads.get(id);
  if (!upload) return;

  upload.progress = progress;
  upload.active = true;
  refreshUploadPresence();
  notifyListeners();
}

export function markUploadInactive(id: string): void {
  const upload = activeUploads.get(id);
  if (!upload) return;

  upload.active = false;
  refreshUploadPresence();
  notifyListeners();
}

export function unregisterUpload(id: string): void {
  activeUploads.delete(id);
  setPendingWarningCount(getUploadCount());
  refreshUploadPresence();
  notifyListeners();
}

export function clearUploads(): void {
  activeUploads.clear();
  setPendingWarningCount(0);
  refreshUploadPresence();
  notifyListeners();
}

export function getUploadCount(): number {
  return Array.from(activeUploads.values()).filter((upload) => upload.active).length;
}

export function getActiveUploads(): UploadInfo[] {
  return Array.from(activeUploads.values())
    .filter((upload) => upload.active)
    .map(cloneUpload);
}

export function hasActiveUploads(): boolean {
  return getUploadCount() > 0;
}

export function getUploadSnapshot(): UploadTrackerSnapshot {
  return {
    uploadCount: getUploadCount(),
    activeUploads: getActiveUploads(),
  };
}

export function subscribeToUploads(listener: () => void): () => void {
  listeners.add(listener);
  refreshNavigationWarningListener();
  listener();
  return () => listeners.delete(listener);
}

export function bindUploadNavigationWarning(onBeforeUnload: (event: BeforeUnloadEvent) => void): () => void {
  if (!hasWindow()) return () => undefined;
  window.addEventListener('beforeunload', onBeforeUnload);
  return () => window.removeEventListener('beforeunload', onBeforeUnload);
}

export function getUploadNavigationWarningState(): UploadNavigationWarningState {
  const snapshot = getUploadSnapshot();
  return {
    ...snapshot,
    isBlocked: snapshot.uploadCount > 0,
    proceed: () => clearUploads(),
    stay: () => undefined,
  };
}

export function getUploadNavigationWarningViewState(): UploadNavigationWarningViewState {
  const state = getUploadNavigationWarningState();
  return {
    ...state,
    isOpen: state.isBlocked,
  };
}

export function getUploadTrackerListenerState(): UploadTrackerListenerState {
  return {
    ...getUploadSnapshot(),
    hasActiveUploads: hasActiveUploads(),
  };
}

