   131	function upsertComment(old: CommentThread[] | undefined, comment: Comment): CommentThread[] {
   132	  const existing = old ?? [];
   133	  let found = false;
   134	
   135	  const next = existing.map((thread) => {
   136	    if (thread.comment_id !== comment.comment_id) return thread;
   137	    found = true;
   138	
   139	    if (thread.root?.id === comment.id) return { ...thread, root: comment };
   140	    if (thread.replies.some((reply) => reply.id === comment.id)) {
   141	      return { ...thread, replies: thread.replies.map((reply) => (reply.id === comment.id ? comment : reply)) };
   142	    }
   143	
   144	    return { ...thread, replies: [...thread.replies, comment] };
   145	  });
   146	
   147	  if (found) return next;
   148	
   149	  return [...next, { comment_id: comment.comment_id, root: comment.parent_id === null ? comment : null, replies: comment.parent_id === null ? [] : [comment] }];
