   146	export async function apiPost(endpoint: string, body?: object): Promise<Response> {
   147	  return fetchWithCsrf(endpoint, 'POST', body);
   148	}
   149	
   150	export async function apiPut(endpoint: string, body?: object): Promise<Response> {
   151	  return fetchWithCsrf(endpoint, 'PUT', body);
   152	}
   153	
   154	export async function apiPatch(endpoint: string, body: object): Promise<Response> {
   155	  return fetchWithCsrf(endpoint, 'PATCH', body);
   156	}
   157	
   158	export async function apiDelete(endpoint: string, body?: object): Promise<Response> {
   159	  return fetchWithCsrf(endpoint, 'DELETE', body);
