   162	async function request<T>(
   163	  endpoint: string,
   164	  options: RequestInit = {}
   165	): Promise<ApiResponse<T>> {
   166	  const headers: Record<string, string> = {
   167	    'Content-Type': 'application/json',
   168	    ...(options.headers as Record<string, string>),
   169	  };
   170	
   171	  // Add CSRF token for state-changing requests
   172	  const method = options.method?.toUpperCase() || 'GET';
   173	  if (['POST', 'PUT', 'PATCH', 'DELETE'].includes(method)) {
   174	    const token = await ensureCsrfToken();
   175	    headers['X-CSRF-Token'] = token;
   176	  }
   177	
   178	  const response = await fetch(`${API_URL}${endpoint}`, {
   179	    ...options,
   180	    credentials: 'include',
   181	    headers,
   182	  });
   183	
   184	  // CloudFront may intercept errors and return HTML - detect and redirect
   185	  if (!isJsonResponse(response)) {
   186	    // On public routes like /invite, return error response instead of redirecting
   187	    if (window.location.pathname.startsWith('/invite')) {
   188	      return {
   189	        success: false,
   190	        error: { code: 'NETWORK_ERROR', message: 'Server returned non-JSON response' },
   191	      } as ApiResponse<T>;
   192	    }
   193	    handleSessionExpired(); // never returns
   194	  }
   195	
   196	  const data: ApiResponse<T> = await response.json();
   197	
   198	  // Handle session expiration - redirect to login with expired=true
   199	  // Only for SESSION_EXPIRED (actual expiration), not UNAUTHORIZED (no session existed)
   200	  // Skip for public routes like /invite where 401 is expected for unauthenticated users
   201	  if (response.status === 401) {
   202	    if (data.error?.code === 'SESSION_EXPIRED') {
   203	      if (!window.location.pathname.startsWith('/invite')) {
   204	        handleSessionExpired(); // never returns - shows "session expired" message
   205	      }
   206	    }
   207	    // UNAUTHORIZED (no session) just returns error - ProtectedRoute will redirect without expired message
   208	    return data;
   209	  }
   210	
   211	  // If CSRF token is invalid, clear and retry once
   212	  if (response.status === 403 && data.error?.code === 'CSRF_ERROR') {
   213	    clearCsrfToken();
   214	    const newToken = await ensureCsrfToken();
   215	    headers['X-CSRF-Token'] = newToken;
   216	    const retryResponse = await fetch(`${API_URL}${endpoint}`, {
   217	      ...options,
   218	      credentials: 'include',
   219	      headers,
   220	    });
   221	    if (!isJsonResponse(retryResponse)) {
   222	      handleSessionExpired(); // never returns
   223	    }
   224	    return retryResponse.json();
   225	  }
   226	
   227	  return data;
   228	}
