   102	/**
   103	 * Handle image upload and insertion into editor
   104	 */
   105	async function handleImageUpload(
   106	  editor: Editor,
   107	  file: File,
   108	  options: ImageUploadOptions
   109	) {
   110	  const signal = options.abortController?.signal;
   111	
   112	  // Check if already aborted (e.g., user navigated away before upload started)
   113	  if (signal?.aborted) {
   114	    return;
   115	  }
   116	
   117	  options.onUploadStart?.(file);
   118	
   119	  // Generate unique upload ID for tracking navigation warnings
   120	  const uploadId = crypto.randomUUID();
   121	  registerUpload(uploadId, file.name);
   122	
   123	  // Insert image with local preview for immediate feedback
   124	  const previewUrl = URL.createObjectURL(file);
   125	  editor
   126	    .chain()
   127	    .focus()
   128	    .setImage({
   129	      src: previewUrl,
   130	      alt: file.name,
   131	      title: file.name,
   132	    })
   133	    .run();
   134	
   135	  // Revoke the preview URL once the image is replaced or upload stops
   136	  const cleanupPreview = () => URL.revokeObjectURL(previewUrl);
   137	
   138	  try {
   139	    const result = await uploadFile(
   140	      file,
   141	      (progress: UploadProgress) => {
   142	        // Update global tracker for navigation warning
   143	        updateUploadProgress(uploadId, progress.progress);
   144	      },
   145	      signal
   146	    );
   147	
   148	    // Check if aborted before updating the editor
   149	    // This prevents updating a stale editor after navigation
   150	    if (signal?.aborted) {
   151	      console.log('Image upload completed but was cancelled - not updating editor');
   152	      return;
   153	    }
   154	
   155	    const uploadedUrl = getUploadedImageUrl(result);
   156	    if (!isImageUploadSupportedUrl(uploadedUrl)) {
   157	      throw new Error('Upload did not return a usable image URL');
   158	    }
   159	
   160	    const { state, view } = editor;
   161	    const { doc } = state;
   162	
   163	    let imagePos: number | null = null;
   164	
   165	    doc.descendants((node: ProseMirrorNode, pos: number) => {
   166	      if (node.type.name === 'image' && node.attrs.src === previewUrl) {
   167	        imagePos = pos;
   168	        return false;
   169	      }
   170	      return true;
   171	    });
   172	
   173	    if (imagePos !== null) {
   174	      const transaction = state.tr.setNodeMarkup(imagePos, undefined, {
   175	        ...doc.nodeAt(imagePos)?.attrs,
   176	        src: uploadedUrl,
   177	      });
   178	      view.dispatch(transaction);
   179	    }
   180	
   181	    // If the preview node is no longer present, insert the persisted image URL
   182	    if (imagePos === null && !signal?.aborted) {
   183	      editor.chain().focus().setImage({ src: uploadedUrl, alt: file.name, title: file.name }).run();
   184	    }
   185	
   186	    cleanupPreview();
   187	    // Upload complete - unregister from tracker
   188	    unregisterUpload(uploadId);
   189	    options.onUploadComplete?.(uploadedUrl);
   190	  } catch (error) {
   191	    // Upload failed - unregister from tracker
   192	    unregisterUpload(uploadId);
   193	    cleanupPreview();
   194	    // Don't report cancellation as an error - it's intentional
   195	    if (error instanceof DOMException && error.name === 'AbortError') {
   196	      console.log('Image upload cancelled');
   197	      return;
   198	    }
   199	
   200	    console.error('Image upload failed:', error);
   201	    options.onUploadError?.(
   202	      error instanceof Error ? error : new Error('Upload failed')
   203	    );
   204	
   205	    // Optionally remove the failed image or show error state
   206	    // For now, leave the preview as fallback
   207	  }
   208	}
