   213	function fileToDataUrl(file: File): Promise<string> {
   214	  return new Promise((resolve, reject) => {
   215	    const reader = new FileReader();
   216	    reader.onload = () => resolve(reader.result as string);
   217	    reader.onerror = reject;
   218	    reader.readAsDataURL(file);
   219	  });
   220	}
