    24	type BacklinkSummary = {
    25	  id: string;
    26	  title: string;
    27	  document_type: string;
    28	};
    29	
    30	type LinkSyncResponse = {
    31	  document_id: string;
    32	  linked_document_ids: string[];
    33	};
    34	
    35	async function assertVisibleDocument(id: string, workspaceId: string, userId: string, isAdmin: boolean) {
    36	  const docResult = await pool.query(
    37	    `SELECT id FROM documents
    38	     WHERE id = $1 AND workspace_id = $2
    39	       AND ${VISIBILITY_FILTER_SQL('documents', '$3', '$4')}`,
    40	    [id, workspaceId, userId, isAdmin]
    41	  );
    42	
    43	  return (docResult.rowCount ?? 0) > 0;
    44	}
    45	
    46	async function validateTargetDocuments(
    47	  targetIds: string[],
    48	  workspaceId: string,
    49	  userId: string,
    50	  isAdmin: boolean
    51	) {
    52	  if (targetIds.length === 0) return true;
    53	
    54	  const targetResult = await pool.query(
    55	    `SELECT id FROM documents
    56	     WHERE id = ANY($1::uuid[]) AND workspace_id = $2
    57	       AND ${VISIBILITY_FILTER_SQL('documents', '$3', '$4')}`,
    58	    [targetIds, workspaceId, userId, isAdmin]
    59	  );
    60	
    61	  return targetResult.rows.length === targetIds.length;
    62	}
    63	
    64	function buildSyncedLinkSet(payload: DocumentLinkPayload) {
    65	  return Array.from(
    66	    new Set([
    67	      ...(payload.target_ids ?? []),
    68	      ...(payload.links ?? []),
    69	      ...(payload.mentions ?? []),
    70	      ...(payload.extracted_links ?? []),
    71	      ...(payload.extracted_mentions ?? []),
    72	    ])
    73	  );
    74	}
