    79	
    80	  const userId = req.userId!;
    81	  const workspaceId = req.workspaceId!;
    82	  const { isAdmin } = await getVisibilityContext(userId, workspaceId);
    83	
    84	  const visible = await assertVisibleDocument(parsedId.data, workspaceId, userId, isAdmin);
    85	  if (!visible) return res.status(404).json({ error: 'Document not found' });
    86	
    87	  const result = await pool.query(
    88	    `SELECT DISTINCT ON (d.id)
    89	        d.id,
    90	        d.document_type,
    91	        d.title
    92	     FROM document_links dl
    93	     JOIN documents d ON dl.source_id = d.id
    94	     WHERE dl.target_id = $1 AND d.workspace_id = $2
    95	       AND ${VISIBILITY_FILTER_SQL('d', '$3', '$4')}
    96	     ORDER BY d.id, dl.created_at DESC, d.created_at DESC`,
    97	    [parsedId.data, workspaceId, userId, isAdmin]
    98	  );
    99	
   100	  return res.json(
   101	    result.rows.map((row) => ({
   102	      id: row.id,
   103	      title: row.title,
   104	      document_type: row.document_type,
   105	    })) as BacklinkSummary[]
