   110	  const parsedId = uuidParamSchema.safeParse(req.params.id);
   111	  if (!parsedId.success) return res.status(400).json({ error: 'Invalid document ID' });
   112	
   113	  const payload = req.body as DocumentLinkPayload;
   114	  const parsed = documentLinkSyncSchema.safeParse({
   115	    target_ids: payload.target_ids ?? [],
   116	    links: payload.links ?? payload.extracted_links ?? [],
   117	    mentions: payload.mentions ?? payload.extracted_mentions ?? [],
   118	  });
   119	  if (!parsed.success) return res.status(400).json({ error: 'Invalid input', details: parsed.error.errors });
   120	  if ((parsed.data.target_ids.length + parsed.data.links.length + parsed.data.mentions.length) === 0) {
   121	    await pool.query('DELETE FROM document_links WHERE source_id = $1', [parsedId.data]);
   122	    return res.status(200).json({ document_id: parsedId.data, linked_document_ids: [] } satisfies LinkSyncResponse);
   123	  }
   124	
   125	  const userId = req.userId!;
   126	  const workspaceId = req.workspaceId!;
   127	  const { isAdmin } = await getVisibilityContext(userId, workspaceId);
   128	  const sourceId = parsedId.data;
   129	  const extractedIds = buildSyncedLinkSet({
   130	    target_ids: parsed.data.target_ids,
   131	    links: parsed.data.links,
   132	    mentions: parsed.data.mentions,
   133	    extracted_links: payload.extracted_links,
   134	    extracted_mentions: payload.extracted_mentions,
   135	  });
   136	
   137	  const visible = await assertVisibleDocument(sourceId, workspaceId, userId, isAdmin);
   138	  if (!visible) return res.status(404).json({ error: 'Document not found' });
   139	
   140	  if (!(await validateTargetDocuments(extractedIds, workspaceId, userId, isAdmin))) {
   141	    return res.status(400).json({ error: 'One or more target documents not found or not visible' });
   142	  }
   143	
   144	  const client = await pool.connect();
   145	  try {
   146	    await client.query('BEGIN');
   147	    await client.query('DELETE FROM document_links WHERE source_id = $1', [sourceId]);
   148	
   149	    if (extractedIds.length > 0) {
   150	      const values = extractedIds.map((_, idx) => `($${idx * 2 + 1}::uuid, $${idx * 2 + 2}::uuid)`).join(', ');
   151	      const params = extractedIds.flatMap((targetId) => [sourceId, targetId]);
   152	      await client.query(
   153	        `INSERT INTO document_links (source_id, target_id)
   154	         VALUES ${values}
   155	         ON CONFLICT (source_id, target_id) DO UPDATE
   156	         SET updated_at = NOW()`,
   157	        params
   158	      );
   159	    }
   160	
   161	    await client.query('COMMIT');
   162	    return res.status(200).json({
   163	      document_id: sourceId,
   164	      linked_document_ids: extractedIds,
   165	    } satisfies LinkSyncResponse);
   166	  } catch (err) {
   167	    await client.query('ROLLBACK');
   168	    throw err;
   169	  } finally {
   170	    client.release();
   171	  }
   172	});
   173	export default router;
